local LCityBase = require("LApp.gameplay.city.base.LCityBase")

---@class LCityPeopleFindPathMgr:LCityBase 主界面场景小人寻路管理
local LCityPeopleFindPathMgr = classX("LCityPeopleFindPathMgr",LCityBase)

function LCityPeopleFindPathMgr:ctor()
    LCityBase.ctor(self)
    self.startId = 0;
    self.endId = 0;
    self.openList = {};
    self.closedList = {};
    --最终路径
    self.pathList = {};
    --路线和临近的路线
    self.idAndNear = {};
    --计算结束回调
    self.callBack = nil;
end

function LCityPeopleFindPathMgr:FindPath(startId,endId,callBack)
    self.callBack = callBack;
    self.startId = startId;
    self.endId = endId;
    table.dispose(self.openList);
    table.dispose(self.closedList);
    table.dispose(self.pathList);
    table.dispose(self.idAndNear);
    local startNode = LineNodeUnit:new();
    startNode:SetData(startId);
    self:GetAllNear();

    table.insert(self.openList,startNode);
    self:BeginFind()
end

function LCityPeopleFindPathMgr:GetAllNear()
    for i, v in pairs(GameTable.PeopleRoadRef) do
        self:AddIdNear(v);
    end
    local endConfig = GameTable.PeopleRoadRef[self.endId];
    self:AddIdNear(endConfig);
end

function LCityPeopleFindPathMgr:AddIdNear(config)
    local near = {}
    if(config == nil)then
        return
    end
    for i, v in pairs(config.connectLines) do
        --if(v == self.endId)then
            table.insert(near,v);
        --end
    end
    if(#near > 0)then
        self.idAndNear[config.refId] = near;
    end
end

function LCityPeopleFindPathMgr:BeginFind()
    local count = self:GetListCount(self.openList);
    if(count > 0)then
        local cur = self.openList[1];
        for i = 1, count do
            local node = self.openList[i];
            if(node.cost < cur.cost)then
                cur = node;
            end
        end
        self:ListRemove(self.openList,cur.lineId);
        self:ListAdd(self.closedList,cur);
        if(self.endId == cur.lineId)then
            --找到路了
            self:GeneratePath(cur);
            return;
        end

        local near = self:GetNodeNear(cur.lineId);
        for i, v in pairs(near) do
            if(not self:CheckInList(self.closedList,v.lineId))then
                local cost = cur.cost + 1;
                --如果新路径到相邻路径的距离更新，或者不在查找列表中
                if(cost < v.cost or not self:CheckInList(self.openList,v.lineId))then
                    --更新数据
                    v.cost = cost;
                    v.parent = cur;
                    if(not self:CheckInList(self.openList,v.lineId))then
                        self:ListAdd(self.openList,v);
                    end
                end
            end
        end
        self:BeginFind();
    else
        self.callBack(nil)
    end
end
function LCityPeopleFindPathMgr:CheckInList(list,id)
    for i, v in pairs(list) do
        if(v.lineId == id)then
            return true;
        end
    end
    return false;
end
function LCityPeopleFindPathMgr:GetNodeNear(id)
    local near = {}
    --if(self.idAndNear == nil or self.idAndNear[id] == nil)then
    --    return near;
    --end

    for i, v in pairs(self.idAndNear[id]) do
        local node = LineNodeUnit:new();
        node:SetData(v);
        table.insert(near,node);
    end
    return near;
end
function LCityPeopleFindPathMgr:GetListCount(list)
    local count = 0;
    if(list == nil)then
        return 0;
    end
    if(next(list))then
        for i, v in pairs(list) do
            count = count + 1;
        end
    end
    return count;
end

function LCityPeopleFindPathMgr:ListRemove(list,id)
    for i, v in pairs(list) do
        if(v.lineId == id)then
            table.remove(list,i);
        end
    end
end

function LCityPeopleFindPathMgr:ListAdd(list,v)
    table.insert(list,v);
end

function LCityPeopleFindPathMgr:GeneratePath(node)
    if( node.parent == nil)then
        if(self.callBack ~= nil)then
            local resutList = {};
            table.insert(resutList,self.startId);
            for i = #self.pathList, 1,-1 do
                table.insert(resutList,self.pathList[i]);
            end
            self.callBack(resutList)
        end
        return
    end
    table.insert(self.pathList,node.lineId);
    self:GeneratePath(node.parent);
end
function LCityPeopleFindPathMgr:Dispose()
    if(self._isDisposed)then
        return;
    end
    self.startId = 0;
    self.endId = 0;
    table.dispose(self.openList);
    self.openList = nil;
    table.dispose(self.closedList);
    self.closedList = nil;
    table.dispose(self.pathList)
    self.pathList = nil;
    table.dispose(self.idAndNear);
    self.idAndNear = nil;
    self.callBack = nil;
    LCityBase.Dispose(self);
end
function LCityPeopleFindPathMgr:Initialize()
    LCityBase.Initialize(self)
end
return LCityPeopleFindPathMgr